    riskFactors: ["Thermal exposure (flame, scald, contact with hot objects)", "Chemical exposure (acids, alkalis, industrial chemicals)", "Electrical injuries (current path determines tissue damage)", "Radiation exposure (sunburn, radiation therapy)", "Inhalation injury from fire in enclosed spaces"],
    diagnostics: ["Burn depth assessment by wound appearance, sensation, and blanching", "TBSA calculation using Rule of Nines or Lund-Browder chart", "Carboxyhemoglobin level if smoke inhalation suspected", "CBC, BMP, lactate, and coagulation studies for major burns"],
    management: ["Stop the burning process and remove contaminated clothing", "Cool burns with room temperature water (not ice) for 20 minutes", "Fluid resuscitation: Parkland formula for burns > 20% TBSA", "Wound care with appropriate dressings; silver sulfadiazine for partial-thickness burns"],
    nursingActions: ["Assess and document burn depth, TBSA, and wound characteristics", "Monitor urine output hourly during fluid resuscitation (target 0.5-1 mL/kg/hr)", "Perform wound care with aseptic technique and prescribed topical agents", "Assess for circumferential burns requiring escharotomy monitoring", "Manage pain aggressively - burns are extremely painful, especially partial-thickness"],
    signs: { left: ["Superficial burn: erythema, pain, no blisters (sunburn pattern)", "Partial-thickness: moist, pink wound with intact blisters, very painful", "Urine output 0.5-1 mL/kg/hr during resuscitation indicating adequate perfusion", "Wound healing with re-epithelialization progressing from wound margins"], right: ["Full-thickness: painless, dry, leathery, white/brown/charred tissue", "Circumferential burns causing compartment syndrome risk", "Inadequate urine output despite fluid resuscitation (burn shock)", "Signs of inhalation injury: singed nasal hairs, hoarseness, carbonaceous sputum"] },
